// ============================================================
// Procesar Mensaje — versión con filtro de audio (Bloque 1 + 2)
// ============================================================

// ── FILTRO fromMe ──────────────────────────────────────────
if ($('Webhook').item.json.body.data.key.fromMe === true) {
  return [];
}

// ── FILTRO AUDIO (detección) ────────────────────────────────
const esAudio = !!$('Webhook').item.json.body.data.message?.audioMessage ||
                !!$('Webhook').item.json.body.data.message?.pttMessage;

// ── DATOS DEL NEGOCIO desde Lookup ─────────────────────────
const negocio = $('Lookup Negocio').item.json;
const businessId        = negocio.id;
const whatsappInstance  = negocio.whatsapp_instance;
const ownerNumber       = negocio.owner_number;
const promptName        = negocio.prompt_name || negocio.name;
const servicesText      = negocio.services_text || '';
const professionalsRaw = negocio.professionals;
let professionals = [];
if (Array.isArray(professionalsRaw)) {
  professionals = professionalsRaw;
} else if (typeof professionalsRaw === 'string' && professionalsRaw) {
  try { professionals = JSON.parse(professionalsRaw); } catch(e) { professionals = []; }
}
const professionalsText = professionals.map(p => p.name).join(', ');
const multiProfessional  = professionals.length > 0;
const timezone          = negocio.timezone || 'America/Bogota';

let scheduleText;
try {
  scheduleText = JSON.parse(negocio.schedule_text || '{}');
} catch(e) {
  scheduleText = {};
}

// ── RATE LIMIT ─────────────────────────────────────────────
const numero = $('Webhook').item.json.body.data.key.remoteJid;
const ahora = Date.now();
const ventana = 60 * 60 * 1000;
const limite = 50;

const historialRaw = $getWorkflowStaticData('global');
if (!historialRaw.rateLimits) historialRaw.rateLimits = {};
const rateLimitKey = `${businessId}_${numero}`;
const historial = historialRaw.rateLimits[rateLimitKey] || [];
const recientes = historial.filter(t => ahora - t < ventana);

if (recientes.length >= limite) return [];

recientes.push(ahora);
historialRaw.rateLimits[rateLimitKey] = recientes;

// ── NÚMERO LIMPIO (movido arriba para usarlo en el filtro de audio) ──
const numeroLimpio = numero.replace('@s.whatsapp.net', '').replace(/\D/g, '');

// ── FILTRO MENSAJES NO-TEXTO ────────────────────────────────
const msg = $('Webhook').item.json.body.data.message || {};
const esNoTexto = !!(
  msg.audioMessage   ||
  msg.pttMessage     ||
  msg.imageMessage   ||
  msg.videoMessage   ||
  msg.stickerMessage ||
  msg.documentMessage||
  msg.locationMessage ||
  msg.liveLocationMessage
);

if (esNoTexto) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${$env.EVOLUTION_API_URL}/message/sendText/${whatsappInstance}`,
    headers: { 'apikey': $env.EVOLUTION_API_KEY, 'Content-Type': 'application/json' },
    body: { number: numeroLimpio, text: 'Solo proceso mensajes de texto 😊 Escríbeme lo que necesitas y con gusto te ayudo.' },
    json: true
  });
  return [];
}

// ── FECHA HOY ───────────────────────────────────────────────
const ahoraTZ = new Date(new Date().toLocaleString('en-US', { timeZone: timezone }));
const dia  = String(ahoraTZ.getDate()).padStart(2, '0');
const mes  = String(ahoraTZ.getMonth() + 1).padStart(2, '0');
const anio = ahoraTZ.getFullYear();
const fechaHoy = `${dia}/${mes}/${anio}`;

// ── CALENDARIO PRÓXIMOS 7 DÍAS ──────────────────────────────
const diasSemana = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];
const manana = new Date(new Date().toLocaleString('en-US', { timeZone: timezone }));
manana.setDate(manana.getDate() + 1);
let calendario = `Mañana: ${String(manana.getDate()).padStart(2,'0')}/${String(manana.getMonth()+1).padStart(2,'0')}/${manana.getFullYear()}\n`;
for (let i = 1; i <= 7; i++) {
  const d = new Date(new Date().toLocaleString('en-US', { timeZone: timezone }));
  d.setDate(d.getDate() + i);
  calendario += `${diasSemana[d.getDay()]}: ${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}\n`;
}

// ── HORARIO TEXTO PARA PROMPT ───────────────────────────────
const toAmPm = h => h < 12 ? `${h === 0 ? 12 : h}:00 AM` : `${h === 12 ? 12 : h-12}:00 PM`;
let horarioTextoPrompt = '';
for (let d = 0; d <= 6; d++) {
  const key = String(d);
  if (scheduleText[key]) {
    const { open, close } = scheduleText[key];
    horarioTextoPrompt += `${diasSemana[d]}: ${toAmPm(open)} - ${toAmPm(close)}\n`;
  } else {
    horarioTextoPrompt += `${diasSemana[d]}: Cerrado\n`;
  }
}

// ── EXTRAER MENSAJE ─────────────────────────────────────────
const mensaje = $('Webhook').item.json.body.data.message?.conversation ||
                $('Webhook').item.json.body.data.message?.extendedTextMessage?.text || '';

// ── VALIDACIÓN DE HORARIO ───────────────────────────────────
function detectarFueraDeHorario(texto, schedule, tzName) {
  const t = (texto || '').toLowerCase()
    .replace(/[áàä]/g,'a').replace(/[éèë]/g,'e')
    .replace(/[íìï]/g,'i').replace(/[óòö]/g,'o')
    .replace(/[úùü]/g,'u');

  const nombresDiasNorm = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
  let diaIndex = null;
  for (let i = 0; i < nombresDiasNorm.length; i++) {
    if (t.includes(nombresDiasNorm[i])) { diaIndex = i; break; }
  }
  if (diaIndex === null) {
    const mf = t.match(/\b(\d{1,2})\/(\d{1,2})\/(\d{4})\b/);
    if (mf) {
      const dFecha = new Date(parseInt(mf[3]), parseInt(mf[2])-1, parseInt(mf[1]));
      diaIndex = dFecha.getDay();
    }
  }
  if (diaIndex === null) {
    const hoyTZ = new Date(new Date().toLocaleString('en-US', { timeZone: tzName }));
    diaIndex = hoyTZ.getDay();
  }

  const config = schedule[String(diaIndex)];
  if (!config) return { fueraDeHorario: true, mensajeHorario: `Lo sentimos, ese día no atendemos. ¿Te puedo agendar en otro día? 😊` };

  const abreH = config.open;
  const cierraH = config.close;
  let hora = null;

  const mHHMM = t.match(/\b(\d{1,2}):(\d{2})\s*([ap]\.?m\.?)?/);
  if (mHHMM) {
    let h = parseInt(mHHMM[1]);
    const m = parseInt(mHHMM[2]);
    const suf = (mHHMM[3] || '').replace(/\./g, '');
    if (suf.startsWith('p') && h < 12) h += 12;
    if (suf.startsWith('a') && h === 12) h = 0;
    hora = h + m / 60;
  }
  if (hora === null) { const mPm = t.match(/\b(\d{1,2})\s*p\.?m\.?\b/); if (mPm) { let h = parseInt(mPm[1]); if (h < 12) h += 12; hora = h; } }
  if (hora === null) { const mAm = t.match(/\b(\d{1,2})\s*a\.?m\.?\b/); if (mAm) { let h = parseInt(mAm[1]); if (h === 12) h = 0; hora = h; } }
  if (hora === null) { const mT = t.match(/(?:a las|las)\s+(\d{1,2})(?:\s+de la|\s+en la)?\s+(?:tarde|noche)/); if (mT) { let h = parseInt(mT[1]); if (h < 12) h += 12; hora = h; } }
  if (hora === null) { const mM = t.match(/(?:a las|las)\s+(\d{1,2})(?:\s+de la)?\s+manana/); if (mM) { let h = parseInt(mM[1]); if (h === 12) h = 0; hora = h; } }

  if (hora === null) return { fueraDeHorario: false };
  if (hora >= abreH && hora < cierraH) return { fueraDeHorario: false };

  return {
    fueraDeHorario: true,
    mensajeHorario: `Lo sentimos, esa hora está fuera de nuestro horario. Atendemos de ${toAmPm(abreH)} a ${toAmPm(cierraH)}. ¿Te puedo agendar en otro horario? 😊`
  };
}

const validacion = detectarFueraDeHorario(mensaje, scheduleText, timezone);

if (!mensaje.trim()) return [];

return [{
  json: {
    textoOriginal:    mensaje,
    numero:           numero,
    numeroLimpio:     numeroLimpio,
    timestamp:        $('Webhook').item.json.body.data.messageTimestamp,
    procesado:        true,
    fechaHoy:         fechaHoy,
    calendario:       calendario,
    fueraDeHorario:   validacion.fueraDeHorario,
    mensajeHorario:   validacion.mensajeHorario || null,
    businessId:       businessId,
    whatsappInstance: whatsappInstance,
    ownerNumber:      ownerNumber,
    promptName:       promptName,
    servicesText:     servicesText,
    horarioTexto:     horarioTextoPrompt,
    professionals:     professionals,
    professionalsText: professionalsText,
    multiProfessional:  multiProfessional
  }
}];

const slots = $input.all();
const diasSemana = ['Domingo','Lunes','Martes','Miércoles','Jueves','Viernes','Sábado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

const porFecha = {};
for (const item of slots) {
  const fecha = item.json.fecha;
  const slot  = item.json.slot;
  if (!porFecha[fecha]) porFecha[fecha] = [];
  porFecha[fecha].push(slot);
}

let disponibilidad = '';
for (const [fecha, horas] of Object.entries(porFecha)) {
  const d = new Date(fecha + 'T00:00:00');
  const nombreDia = diasSemana[d.getUTCDay()];
  const dia = d.getUTCDate();
  const mes = meses[d.getUTCMonth()];
  disponibilidad += `${nombreDia} ${dia} de ${mes}: ${horas.join(', ')}\n`;
}

let sesionContexto = '';
let debugSesion = '';
const _diasSC = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const _mesesSC = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
function _fechaNatSC(f){ const dd=new Date(f+'T00:00:00'); return `${_diasSC[dd.getUTCDay()]} ${dd.getUTCDate()} de ${_mesesSC[dd.getUTCMonth()]}`; }
function _horaAmPmSC(h){ const hh=(h||'').substring(0,5); const p=hh.split(':').map(Number); const a=p[0], b=p[1]; const ap=a<12?'AM':'PM'; const h12=a===0?12:a>12?a-12:a; return `${h12}:${String(b).padStart(2,'0')} ${ap}`; }
try {
  const sesion = $('Leer Sesión activa').first().json;
  debugSesion = JSON.stringify(sesion);
  if (sesion && sesion.id) {
    const citas = Array.isArray(sesion.citas) ? sesion.citas : JSON.parse(sesion.citas);
    if (citas && citas.length > 0) {
      sesionContexto = `\nSESIÓN ACTIVA — El cliente está en proceso de ${sesion.accion} una cita.\nCITAS DISPONIBLES PARA SELECCIÓN:\n`;
      citas.forEach((c, i) => {
        sesionContexto += `Opción ${i+1}: ID_CITA=${c.id} | ${c.servicio} | ${_fechaNatSC(c.fecha)} | ${_horaAmPmSC(c.hora)}\n`;
      });
      sesionContexto += `\nUsa EXACTAMENTE el día y la hora mostrados arriba (ya vienen en lenguaje natural y AM/PM). NUNCA recalcules el día de la semana por tu cuenta.\nCuando el cliente diga un número (1, 2, etc.), usa el ID_CITA correspondiente para emitir el código de acción.\n`;
    }
  }
} catch(e) {
  debugSesion = 'error: ' + e.message;
}

const prev = $('Procesar Mensaje').item.json;
return [{
  json: {
    ...prev,
    disponibilidad: disponibilidad || 'Sin disponibilidad en los próximos 7 días',
    sesionContexto,
    debugSesion
  }
}];

const total  = $input.first().json.total;
const numero = ($('Procesar Mensaje').item.json.numero || '').replace(/@s\.whatsapp\.net/g, '').replace(/\D/g, '');
const partes = $('AI Agent').item.json.output.split('|');
  const professionalName = (partes[4] || '').trim();
return [{ json: {
  disponible:        total == 0,
  fechaDeseada:      partes[2]?.trim(),
  horaDeseada:       partes[3]?.split('\n')[0].trim(),
  numero,
  businessId:        $('Procesar Mensaje').item.json.businessId,
  whatsappInstance:  $('Procesar Mensaje').item.json.whatsappInstance,
  professionalName,
  ownerNumber:       $('Procesar Mensaje').item.json.ownerNumber
} }];

const output = $('AI Agent').item.json.output.split('|');
const servicio = output[1] || '';
const fecha = output[2] || '';
const hora = (output[3] || '').split('\n')[0].trim();
const nombre = $('Webhook').item.json.body.data.pushName || 'Cliente';
const numero = ($('Procesar Mensaje').item.json.numero || '').replace('@s.whatsapp.net', '');

const ownerNumber = $('Verificar Slot').item.json.ownerNumber;
const whatsappInstance = $('Verificar Slot').item.json.whatsappInstance;
const promptName = $('Procesar Mensaje').item.json.promptName;
const professionalName = $('Verificar Slot').item.json.professionalName;

// Fecha DD/MM/YYYY → lenguaje natural
const diasSemana = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
let fechaNatural = fecha;
try {
  const [dd, mm, yyyy] = fecha.split('/');
  const d = new Date(parseInt(yyyy), parseInt(mm)-1, parseInt(dd));
  fechaNatural = `${diasSemana[d.getDay()]} ${d.getDate()} de ${meses[d.getMonth()]}`;
} catch(e) {}

// Hora → AM/PM (maneja HH:MM y HH:MM AM/PM)
let horaAmPm = hora;
try {
  const matchAmPm = hora.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/i);
  if (matchAmPm) {
    // Ya viene con AM/PM — normalizar formato
    let h = Number(matchAmPm[1]);
    const m = matchAmPm[2];
    const suffix = matchAmPm[3].toUpperCase();
    if (suffix === 'PM' && h !== 12) h += 12;
    if (suffix === 'AM' && h === 12) h = 0;
    const ampm2 = h < 12 ? 'AM' : 'PM';
    const h12 = h === 0 ? 12 : h > 12 ? h - 12 : h;
    horaAmPm = `${h12}:${m} ${ampm2}`;
  } else {
    // Formato 24h HH:MM
    const [hh, min] = hora.split(':').map(Number);
    const ampm = hh < 12 ? 'AM' : 'PM';
    const h12 = hh === 0 ? 12 : hh > 12 ? hh - 12 : hh;
    horaAmPm = `${h12}:${String(min).padStart(2,'0')} ${ampm}`;
  }
} catch(e) {}

const profLine = professionalName ? `\n👤 *Profesional:* ${professionalName}` : '';
const textoDueno = `🔔 *Nueva cita agendada*\n\n👤 *Cliente:* ${nombre}\n📞 *Número:* ${numero}\n✂️ *Servicio:* ${servicio}${profLine}\n📅 *Fecha:* ${fechaNatural}\n⏰ *Hora:* ${horaAmPm}\n\n_Estado: Pendiente_ ✅`;
const profLineCliente = professionalName ? `\n👤 *Profesional:* ${professionalName}` : '';
const textoCliente = `✅ ¡Tu cita quedó confirmada!\n\n✂️ *Servicio:* ${servicio}${profLineCliente}\n📅 *Fecha:* ${fechaNatural}\n⏰ *Hora:* ${horaAmPm}\n\n¡Te esperamos en ${promptName}! 💇‍♂️\nCualquier cambio, escríbenos aquí mismo 😊`;

return [{
  json: {
    ownerNumber,
    whatsappInstance,
    numeroCliente: numero,
    nombreCliente: nombre,
    servicio,
    fecha,
    hora,
    textoDueno,
    textoCliente,
    bodyDueno: JSON.stringify({ number: ownerNumber, text: textoDueno }),
    bodyCliente: JSON.stringify({ number: numero, text: textoCliente })
  }
}];

const citas = $input.all();
const outputRaw = $('AI Agent').item.json.output;
const matchAccion = outputRaw.match(/GESTIONAR_CITA\|(cancelar|reagendar)/);
const accion = matchAccion ? matchAccion[1] : 'cancelar';
const numero = $('Procesar Mensaje').item.json.numeroLimpio;
const whatsappInstance = $('Procesar Mensaje').item.json.whatsappInstance;
const businessId = $('Procesar Mensaje').item.json.businessId;

const diasSemana = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

let listaCitas = '';
const citasParaSession = [];

citas.forEach((item, i) => {
  const c = item.json;
  if (!c || !c.hora || !c.fecha || !c.id) return;
  const d = new Date(c.fecha + 'T00:00:00');
  const fechaNatural = `${diasSemana[d.getUTCDay()]} ${d.getUTCDate()} de ${meses[d.getUTCMonth()]}`;
  const hora = c.hora.substring(0, 5);
  const [hh, mm] = hora.split(':').map(Number);
  const ampm = hh < 12 ? 'AM' : 'PM';
  const h12 = hh === 0 ? 12 : hh > 12 ? hh - 12 : hh;
  const horaAmPm = `${h12}:${String(mm).padStart(2,'0')} ${ampm}`;
  listaCitas += `${i + 1}. ${c.servicio} — ${fechaNatural} a las ${horaAmPm}\n`;
  citasParaSession.push({ id: c.id, servicio: c.servicio, fecha: c.fecha, hora });
});

let mensaje = '';
if (citasParaSession.length === 0) {
  mensaje = `No encontramos citas próximas agendadas a tu número. ¿Puedo ayudarte con algo más? 😊`;
} else if (citasParaSession.length === 1) {
  const verbo = accion === 'cancelar' ? 'cancelar' : 'reagendar';
  mensaje = `Encontré esta cita:\n\n${listaCitas}\n¿Confirmas que deseas ${verbo}? Responde *sí* o con *1* para confirmar 😊`;
} else {
  if (accion === 'cancelar') {
    mensaje = `Encontré estas citas próximas:\n\n${listaCitas}\nResponde con el número de la cita que deseas cancelar 😊`;
  } else {
    mensaje = `Encontré estas citas próximas:\n\n${listaCitas}\nResponde con el número de la cita que deseas reagendar y te ayudo a elegir el nuevo horario 😊`;
  }
}

return [{ json: {
  numero,
  whatsappInstance,
  businessId,
  accion,
  tieneCitas: citasParaSession.length > 0,
  mensaje,
  citasIds: citasParaSession,
  citasJSON: JSON.stringify(citasParaSession)
}}];

